        spacingAroundRangeOperatorRuleAssertThat(code)
            .hasLintViolations(
                LintViolation(4, 21, "Unexpected spacing around \"..\""),
                LintViolation(6, 21, "Unexpected spacing around \"..<\""),
            ).isFormattedAs(formattedCode)
    }
}
